// Calling initializeApp({ ... }, 'name') multiple times will add more FirebaseApps into the FIREBASE_APPS
// injection scope. This allows developers to more easily work with multiple Firebase Applications. Downside
// is that DI for app name and options doesn't really make sense anymore.
export function provideFirebaseApp(fn: (injector: Injector) => IFirebaseApp, ...deps: any[]): EnvironmentProviders {
  return makeEnvironmentProviders([
    DEFAULT_FIREBASE_APP_PROVIDER,
    FIREBASE_APPS_PROVIDER,
    {
      provide: PROVIDED_FIREBASE_APPS,
      useFactory: firebaseAppFactory(fn),
      multi: true,
      deps: [
        NgZone,
        Injector,
        ɵAngularFireSchedulers,
        ...deps,
      ],
    }
  ])
}

register(data?: any): Observable<NbAuthResult> {
  const module = 'register';
  const method = this.getOption(`${module}.method`);
  const url = this.getActionEndpoint(module);
  const requireValidToken = this.getOption(`${module}.requireValidToken`);
  return this.http.request(method, url, { body: data, observe: 'response', headers: this.getHeaders() }).pipe(
    map((res) => {
      if (this.getOption(`${module}.alwaysFail`)) {
        throw this.createFailResponse(data);
      }

      return res;
    }),
    map((res) => {
      return new NbAuthResult(
        true,
        res,
        this.getOption(`${module}.redirect.success`),
        [],
        this.getOption('messages.getter')(module, res, this.options),
        this.createToken(this.getOption('token.getter')('login', res, this.options), requireValidToken),
      );
    }),
    catchError((res) => {
      return this.handleResponseError(res, module);
    }),
  );
}

private scheduleBucket(bucket: IdleBucket, options?: IdleRequestOptions) {
  if (bucket.idleId !== null) {
    return;
  }

  const key = getIdleRequestKey(options);
  const callback = (deadline?: IdleDeadline) => {
    this.cancelBucket(bucket);

    for (const cb of bucket.queue) {
      cb();
      // _tick here is an optimized change detection check and is safe to call here.
      // We also account for the time it takes to run change detection
      // for the newly-created view as a part of the same idle callback.
      this.applicationRef._tick();
      bucket.queue.delete(cb);
      this.callbackBucket.delete(cb);

      if (deadline && deadline.timeRemaining() === 0 && !deadline.didTimeout) {
        break;
      }
    }

    if (bucket.queue.size > 0) {
      this.scheduleBucket(bucket, options);
    } else {
      this.buckets.delete(key);
    }
  };

  // Ensure that the callback runs in the NgZone since
  // the `requestIdleCallback` is not currently patched by Zone.js.
  bucket.idleId = this.idleService.requestOnIdle(
    (deadline) => this.ngZone.run(() => callback(deadline)),
    options,
  );
}

function createNode(
  routeReuseStrategy: RouteReuseStrategy,
  curr: TreeNode<ActivatedRouteSnapshot>,
  prevState?: TreeNode<ActivatedRoute>,
): TreeNode<ActivatedRoute> {
  // reuse an activated route that is currently displayed on the screen
  if (prevState && routeReuseStrategy.shouldReuseRoute(curr.value, prevState.value.snapshot)) {
    const value = prevState.value;
    value._futureSnapshot = curr.value;
    const children = createOrReuseChildren(routeReuseStrategy, curr, prevState);
    return new TreeNode<ActivatedRoute>(value, children);
  } else {
    if (routeReuseStrategy.shouldAttach(curr.value)) {
      // retrieve an activated route that is used to be displayed, but is not currently displayed
      const detachedRouteHandle = routeReuseStrategy.retrieve(curr.value);
      if (detachedRouteHandle !== null) {
        const tree = (detachedRouteHandle as DetachedRouteHandleInternal).route;
        tree.value._futureSnapshot = curr.value;
        tree.children = curr.children.map((c) => createNode(routeReuseStrategy, c));
        return tree;
      }
    }

    const value = createActivatedRoute(curr.value);
    const children = curr.children.map((c) => createNode(routeReuseStrategy, c));
    return new TreeNode<ActivatedRoute>(value, children);
  }
}

getNamedSvgIcon(name: string, namespace: string = ''): Observable<SVGElement> {
  const key = iconKey(namespace, name);
  let config = this._svgIconConfigs.get(key);

  // Return (copy of) cached icon if possible.
  if (config) {
    return this._getSvgFromConfig(config);
  }

  // Otherwise try to resolve the config from one of the resolver functions.
  config = this._getIconConfigFromResolvers(namespace, name);

  if (config) {
    this._svgIconConfigs.set(key, config);
    return this._getSvgFromConfig(config);
  }

  // See if we have any icon sets registered for the namespace.
  const iconSetConfigs = this._iconSetConfigs.get(namespace);

  if (iconSetConfigs) {
    return this._getSvgFromIconSetConfigs(name, iconSetConfigs);
  }

  return observableThrow(getMatIconNameNotFoundError(key));
}

ngOnDestroy() {
  this._resolvers = [];
  this._svgIconConfigs.clear();
  this._iconSetConfigs.clear();
  this._cachedIconsByUrl.clear();
}

private _createOverlay(config: MatSnackBarConfig): OverlayRef {
  const overlayConfig = new OverlayConfig();
  overlayConfig.direction = config.direction;

  const positionStrategy = createGlobalPositionStrategy(this._injector);
  // Set horizontal position.
  const isRtl = config.direction === 'rtl';
  const isLeft =
    config.horizontalPosition === 'left' ||
    (config.horizontalPosition === 'start' && !isRtl) ||
    (config.horizontalPosition === 'end' && isRtl);
  const isRight = !isLeft && config.horizontalPosition !== 'center';
  if (isLeft) {
    positionStrategy.left('0');
  } else if (isRight) {
    positionStrategy.right('0');
  } else {
    positionStrategy.centerHorizontally();
  }
  // Set horizontal position.
  if (config.verticalPosition === 'top') {
    positionStrategy.top('0');
  } else {
    positionStrategy.bottom('0');
  }

  overlayConfig.positionStrategy = positionStrategy;
  overlayConfig.disableAnimations = this._animationsDisabled;
  return createOverlayRef(this._injector, overlayConfig);
}

private _patchContexts(state: DatepickerViewModel) {
	const { months, displayMonths, selectedDate, focusDate, focusVisible, disabled, outsideDays } = state;
	state.months.forEach((month) => {
		month.weeks.forEach((week) => {
			week.days.forEach((day) => {
				// patch focus flag
				if (focusDate) {
					day.context.focused = focusDate.equals(day.date) && focusVisible;
				}

				// calculating tabindex
				day.tabindex =
					!disabled && focusDate && day.date.equals(focusDate) && focusDate.month === month.number ? 0 : -1;

				// override context disabled
				if (disabled === true) {
					day.context.disabled = true;
				}

				// patch selection flag
				if (selectedDate !== undefined) {
					day.context.selected = selectedDate !== null && selectedDate.equals(day.date);
				}

				// visibility
				if (month.number !== day.date.month) {
					day.hidden =
						outsideDays === 'hidden' ||
						outsideDays === 'collapsed' ||
						(displayMonths > 1 &&
							day.date.after(months[0].firstDate) &&
							day.date.before(months[displayMonths - 1].lastDate));
				}
			});
		});
	});
}

export function patchState<State extends object>(
  stateSource: WritableStateSource<State>,
  ...updaters: Array<
    Partial<NoInfer<State>> | PartialStateUpdater<NoInfer<State>>
  >
): void {
  const currentState = untracked(() => getState(stateSource));
  const newState = updaters.reduce(
    (nextState: State, updater) => ({
      ...nextState,
      ...(typeof updater === 'function' ? updater(nextState) : updater),
    }),
    currentState
  );

  const signals = stateSource[STATE_SOURCE];
  const stateKeys = Reflect.ownKeys(stateSource[STATE_SOURCE]);

  for (const key of Reflect.ownKeys(newState)) {
    if (stateKeys.includes(key)) {
      const signalKey = key as keyof State;
      if (currentState[signalKey] !== newState[signalKey]) {
        signals[signalKey].set(newState[signalKey]);
      }
    } else if (typeof ngDevMode !== 'undefined' && ngDevMode) {
      console.warn(
        `@ngrx/signals: patchState was called with an unknown state slice '${String(
          key
        )}'.`,
        'Ensure that all state properties are explicitly defined in the initial state.',
        'Updates to properties not present in the initial state will be ignored.'
      );
    }
  }

  notifyWatchers(stateSource);
}

export function createSelectorsFactory<T>() {
  function getSelectors(): EntitySelectors<T, EntityState<T>>;
  function getSelectors<V>(
    selectState: (state: V) => EntityState<T>
  ): MemoizedEntitySelectors<T, V>;
  function getSelectors(
    selectState?: (state: any) => EntityState<T>
  ): EntitySelectors<T, any> {
    const selectIds = (state: any) => state.ids;
    const selectEntities = (state: EntityState<T>) => state.entities;
    const selectAll = createSelector(
      selectIds,
      selectEntities,
      (ids, entities): any => ids.map((id: any) => (entities as any)[id])
    );

    const selectTotal = createSelector(selectIds, (ids) => ids.length);

    if (!selectState) {
      return {
        selectIds,
        selectEntities,
        selectAll,
        selectTotal,
      };
    }

    return {
      selectIds: createSelector(selectState, selectIds),
      selectEntities: createSelector(selectState, selectEntities),
      selectAll: createSelector(selectState, selectAll),
      selectTotal: createSelector(selectState, selectTotal),
    };
  }

  return { getSelectors };
}

addConfig(config: ConfigOption | ConfigOption[]) {
  if (Array.isArray(config)) {
    config.forEach((c) => this.addConfig(c));
    return;
  }

  if (config.types) {
    config.types.forEach((type) => this.setType(type));
  }
  if (config.validators) {
    config.validators.forEach((validator) => this.setValidator(validator));
  }
  if (config.wrappers) {
    config.wrappers.forEach((wrapper) => this.setWrapper(wrapper));
  }
  if (config.validationMessages) {
    config.validationMessages.forEach((validation) => this.addValidatorMessage(validation.name, validation.message));
  }
  if (config.extensions) {
    this.setSortedExtensions(config.extensions);
  }
  if (config.extras) {
    this.extras = { ...this.extras, ...config.extras };
  }
  if (config.presets) {
    this.presets = {
      ...this.presets,
      ...config.presets.reduce((acc, curr) => ({ ...acc, [curr.name]: curr.config }), {}),
    };
  }
}

onOptionSelect(event, option, index = -1) {
    if (this.$disabled() || this.isOptionDisabled(option) || this.readonly) {
        return;
    }

    event && this.onClick.emit({ originalEvent: event, option, value: this.value });
    this.multiple ? this.onOptionSelectMultiple(event, option) : this.onOptionSelectSingle(event, option);
    this.optionTouched = false;
    index !== -1 && this.focusedOptionIndex.set(index);
}

onOptionSelectMultiple(event, option) {
    let selected = this.isSelected(option);
    let value: any[] = [];
    let metaSelection = this.optionTouched ? false : this.metaKeySelection;

    if (metaSelection) {
        let metaKey = event.metaKey || event.ctrlKey;

        if (selected) {
            value = metaKey ? this.removeOption(option) : [this.getOptionValue(option)];
        } else {
            value = metaKey ? this.modelValue() || [] : [];
            value = [...(value || []), this.getOptionValue(option)];
        }
    } else {
        value = selected ? this.removeOption(option) : [...(this.modelValue() || []), this.getOptionValue(option)];
    }

    this.updateModel(value, event);
}

export function registerOutsideClick(renderer: Renderer2,
                                     options: ListenOptions) {
  if (!options.outsideClick) {
    return Function.prototype;
  }

  // eslint-disable-next-line @typescript-eslint/no-explicit-any
  return renderer.listen('document', 'click', (event: any) => {
    if (options.target && options.target.contains(event.target)) {
      return;
    }
    if (
      options.targets &&
      options.targets.some(target => target.contains(event.target))
    ) {
      return;
    }

    if (options.hide) {
      options.hide();
    }
  });
}

export function registerEscClick(renderer: Renderer2,
                                 options: ListenOptions) {
  if (!options.outsideEsc) {
    return Function.prototype;
  }

  return renderer.listen('document', 'keyup.esc', (event) => {
    if (options.target && options.target.contains(event.target)) {
      return;
    }
    if (
      options.targets &&
      options.targets.some(target => target.contains(event.target))
    ) {
      return;
    }

    if (options.hide) {
      options.hide();
    }
  });
}

override connect(collectionViewer: CollectionViewer): Observable<FlatNode[]> {
  const changed = this._treeControl.expansionModel.changed;
  if (!changed) {
    throw new Error('Unable to subscribe to the expansion model change');
  }
  const s = changed.subscribe((change: SelectionChange<FlatNode>) => {
    if (change.added) {
      change.added.forEach((node) => this._toggleNode(node, true));
    }
    if (change.removed) {
      change.removed.reverse().forEach((node) => this._toggleNode(node, false));
    }
  });
  this._subscriptions.push(s);

  const changes = [
    collectionViewer.viewChange,
    this._treeControl.expansionModel.changed,
    this._data,
  ];

  return merge<unknown[]>(...changes).pipe(
    map(() => {
      this._expandedData.next(
        this._treeFlattener.expandFlattenedNodes(this.data, this._treeControl),
      );
      return this._expandedData.value;
    }),
  );
}

export class ɵZoneScheduler implements SchedulerLike {
  constructor(private zone: any, private delegate: any = queueScheduler) {
  }

  now() {
    return this.delegate.now();
  }

  schedule(work: (this: SchedulerAction<any>, state?: any) => void, delay?: number, state?: any): Subscription {
    const targetZone = this.zone;
    // Wrap the specified work function to make sure that if nested scheduling takes place the
    // work is executed in the correct zone
    const workInZone = function(this: SchedulerAction<any>, state: any) {
      if (targetZone) {
        targetZone.runGuarded(() => {
          work.apply(this, [state]);
        });
      } else {
        work.apply(this, [state]);
      }
    };

    // Scheduling itself needs to be run in zone to ensure setInterval calls for async scheduling are done
    // inside the correct zone. This scheduler needs to schedule asynchronously always to ensure that
    // firebase emissions are never synchronous. Specifying a delay causes issues with the queueScheduler delegate.
    return this.delegate.schedule(workInZone, delay, state);
  }
}

export function ngbPositioning() {
	const rtl = inject(NgbRTL);
	let popperInstance: Instance | null = null;

	return {
		createPopper(positioningOption: PositioningOptions) {
			if (!popperInstance) {
				const updatePopperOptions = positioningOption.updatePopperOptions || noop;
				let popperOptions = updatePopperOptions(getPopperOptions(positioningOption, rtl));
				popperInstance = createPopperLite(
					positioningOption.hostElement,
					positioningOption.targetElement,
					popperOptions,
				);
			}
		},
		update() {
			if (popperInstance) {
				popperInstance.update();
			}
		},
		setOptions(positioningOption: PositioningOptions) {
			if (popperInstance) {
				const updatePopperOptions = positioningOption.updatePopperOptions || noop;
				let popperOptions = updatePopperOptions(getPopperOptions(positioningOption, rtl));
				popperInstance.setOptions(popperOptions);
			}
		},
		destroy() {
			if (popperInstance) {
				popperInstance.destroy();
				popperInstance = null;
			}
		},
	};
}

export function getCreateEffectMetadata<T extends Record<keyof T, Object>>(
  instance: T
): EffectMetadata<T>[] {
  const propertyNames = Object.getOwnPropertyNames(instance) as Array<keyof T>;

  const metadata: EffectMetadata<T>[] = propertyNames
    .filter((propertyName) => {
      if (
        instance[propertyName] &&
        instance[propertyName].hasOwnProperty(CREATE_EFFECT_METADATA_KEY)
      ) {
        // If the property type has overridden `hasOwnProperty` we need to ensure
        // that the metadata is valid (containing a `dispatch` property)
        // https://github.com/ngrx/platform/issues/2975
        const property = instance[propertyName] as any;
        return property[CREATE_EFFECT_METADATA_KEY].hasOwnProperty('dispatch');
      }
      return false;
    })
    .map((propertyName) => {
      const metaData = (instance[propertyName] as any)[
        CREATE_EFFECT_METADATA_KEY
      ];
      return {
        propertyName,
        ...metaData,
      };
    });

  return metadata;
}

private evalExpr(field: FormlyFieldConfigCache, prop: string, value: any) {
  if (prop.indexOf('model.') === 0) {
    const key = prop.replace(/^model\./, ''),
      parent = field.fieldGroup ? field : field.parent;

    let control = field?.key === key ? field.formControl : field.form.get(key);
    if (!control && field.get(key)) {
      control = field.get(key).formControl;
    }
    assignFieldValue({ key, parent, model: field.model }, value);
    if (control && !(isNil(control.value) && isNil(value)) && control.value !== value) {
      control.patchValue(value);
    }
  } else {
    try {
      let target: any = field;
      const paths = this._evalExpressionPath(field, prop);
      const lastIndex = paths.length - 1;
      for (let i = 0; i < lastIndex; i++) {
        target = target[paths[i]];
      }

      target[paths[lastIndex]] = value;
    } catch (error: any) {
      error.message = `[Formly Error] [Expression "${prop}"] ${error.message}`;
      throw error;
    }

    if (['templateOptions.disabled', 'props.disabled'].includes(prop) && hasKey(field)) {
      this.changeDisabledState(field, value);
    }
  }

  this.emitExpressionChanges(field, prop, value);
}

get errorMessage() {
  const fieldForm = this.field.formControl;
  for (const error in fieldForm.errors) {
    if (fieldForm.errors.hasOwnProperty(error)) {
      let message = this.config.getValidatorMessage(error);

      if (isObject(fieldForm.errors[error])) {
        if (fieldForm.errors[error].errorPath) {
          return undefined;
        }

        if (fieldForm.errors[error].message) {
          message = fieldForm.errors[error].message;
        }
      }

      if (this.field.validation?.messages?.[error]) {
        message = this.field.validation.messages[error];
      }

      if (this.field.validators?.[error]?.message) {
        message = this.field.validators[error].message;
      }

      if (this.field.asyncValidators?.[error]?.message) {
        message = this.field.asyncValidators[error].message;
      }

      if (typeof message === 'function') {
        return message(fieldForm.errors[error], this.field);
      }

      return message;
    }
  }

  return undefined;
}

searchOptions(event, char) {
    this.searchValue = (this.searchValue || '') + char;

    let optionIndex = -1;
    let matched = false;

    optionIndex = this.visibleOptions().findIndex((option) => this.isOptionMatched(option));

    if (optionIndex !== -1) {
        matched = true;
    }

    if (optionIndex === -1 && this.focusedOptionIndex() === -1) {
        optionIndex = this.findFirstFocusedOptionIndex();
    }

    if (optionIndex !== -1) {
        setTimeout(() => {
            this.changeFocusedOptionIndex(event, optionIndex);
        });
    }

    if (this.searchTimeout) {
        clearTimeout(this.searchTimeout);
    }

    this.searchTimeout = setTimeout(() => {
        this.searchValue = '';
        this.searchTimeout = null;
    }, 500);

    return matched;
}

isOptionMatched(option) {
    return this.isValidOption(option) && this.getOptionLabel(option).toString().toLocaleLowerCase(this.filterLocale).startsWith(this.searchValue?.toLocaleLowerCase(this.filterLocale));
}

export function listenToTriggers(renderer: Renderer2,
                                 // eslint-disable-next-line @typescript-eslint/no-explicit-any
                                 target: any,
                                 triggers: string,
                                 showFn: BsEventCallback,
                                 hideFn: BsEventCallback,
                                 toggleFn: BsEventCallback): () => void {
  const parsedTriggers = parseTriggers(triggers);
  const listeners: Array<() => void> = [];

  if (parsedTriggers.length === 1 && parsedTriggers[0].isManual()) {
    return Function.prototype as () => void;
  }

  parsedTriggers.forEach((trigger: Trigger) => {
    if (trigger.open === trigger.close) {
      listeners.push(renderer.listen(target, trigger.open, toggleFn));

      return;
    }

    listeners.push(renderer.listen(target, trigger.open, showFn));
    if (trigger.close) {
      listeners.push(renderer.listen(target, trigger.close, hideFn));
    }
  });

  return () => {
    listeners.forEach((unsubscribeFn) => unsubscribeFn());
  };
}

constructor(
  rendererFactory: RendererFactory2,
  @Inject(PLATFORM_ID) platformId: number
) {

  if (isPlatformBrowser(platformId)) {
    // Zoneless-compatible: no NgZone dependency needed
    // Event listeners run without triggering change detection
    this.triggerEvent$ = merge(
      fromEvent(window, 'scroll', { passive: true }),
      fromEvent(window, 'resize', { passive: true }),
      of(0, animationFrameScheduler),
      this.update$$
    );

    this.triggerEvent$.pipe(takeUntilDestroyed()).subscribe(() => {
      if (this.isDisabled) {
        return;
      }

      this.positionElements
      // eslint-disable-next-line @typescript-eslint/no-explicit-any
        .forEach((positionElement: any) => {
          positionElements(
            _getHtmlElement(positionElement.target),
            _getHtmlElement(positionElement.element),
            positionElement.attachment,
            positionElement.appendToBody,
            this.options,
            rendererFactory.createRenderer(null, null)
          );
        });
    });
  }
}

private renderTableOfContents(element: HTMLElement): void {
  if (!this.hasToc()) {
    return;
  }

  let firstHeading = element.querySelector<HTMLElement>('h2,h3[id]');
  if (!firstHeading) {
    return;
  }

  // If the first header is in a card container element, place TOC element
  // before the container.
  const parentEl = firstHeading.parentElement;
  if (parentEl && parentEl.classList.contains('docs-card-container-header')) {
    firstHeading = parentEl.parentElement;
  }

  // Since the content of the main area is dynamically created and there is
  // no host element for a ToC component, we create it manually.
  let tocHostElement: HTMLElement | null = element.querySelector(TOC_HOST_ELEMENT_NAME);
  if (!tocHostElement) {
    tocHostElement = this.document.createElement(TOC_HOST_ELEMENT_NAME);
    tocHostElement.setAttribute(TOC_SKIP_CONTENT_MARKER, 'true');
    firstHeading?.parentNode?.insertBefore(tocHostElement, firstHeading);
  }

  this.renderComponent(TableOfContents, tocHostElement, {contentSourceElement: element});
}

private _getNode(lView: LView, data: any, idx: number): ComponentTreeNode {
  const directives: DirectiveInstanceType[] = [];
  let component: ComponentInstanceType | null = null;
  const tNode = data[idx];
  const node = lView[idx][ELEMENT];
  const element = (node.tagName || node.nodeName).toLowerCase();
  if (!tNode) {
    return {
      nativeElement: node,
      children: [],
      element,
      directives: [],
      component: null,
      controlFlowBlock: null, // neither there will be any control flow block
    };
  }
  for (let i = tNode.directiveStart; i < tNode.directiveEnd; i++) {
    const instance = lView[i];
    const dirMeta = data[i];
    if (dirMeta && dirMeta.template) {
      component = {
        name: element,
        isElement: isCustomElement(node),
        instance,
      };
    } else if (dirMeta) {
      directives.push({
        name: getDirectiveName(instance),
        instance,
      });
    }
  }
  return {
    nativeElement: node,
    children: [],
    element,
    directives,
    component,
    controlFlowBlock: null, // neither there will be any control flow block
  };
}

